# Map the full chain for patrol 4
python3 << 'PYEOF'
import json
with open("/tmp/steps4.json") as f:
    data = json.load(f)
chain = {}
for s in data:
    block_deps = [d for d in s.get("dependencies", []) if d["type"] == "blocks"]
    blocked_by = [d["depends_on_id"] for d in block_deps if d["depends_on_id"] != s.get("parent")]
    chain[s["id"]] = {"title": s["title"], "blocked_by": blocked_by}

# Build execution order
done = set()
order = []
while len(order) < len(chain):
    for k, v in chain.items():
        if k not in done and all(b in done for b in v["blocked_by"]):
            order.append((k, v["title"]))
            done.add(k)
            break
for k, t in order:
    print(k, t)
PYEOF

